            FETCH cur_firm_name INTO cur_firm_name_rec;
            IF cur_firm_name%NOTFOUND THEN
                UPDATE Firms SET firm_name = new_firm_name WHERE firm_name = old_name; 
            ELSE
                CLOSE cur_firm_name;
                RAISE firm_name_exists_exception;
            END IF;
            COMMIT;
            EXIT;
        EXCEPTION 
            WHEN firm_name_exists_exception THEN
                ROLLBACK;
                new_firm_name := new_firm_name || ' (1)';
                DBMS_OUTPUT.PUT_LINE('EXISTS ERROR');
            WHEN OTHERS THEN
                ROLLBACK;
                DBMS_OUTPUT.PUT_LINE('OTHERS ERROR' || SQLERRM);
        END;

        CLOSE cur_firm_name; -- закрываем курсор перед переоткрытием
        EXIT WHEN cur_firm_name%NOTFOUND; -- выходим из цикла, если запись не найдена
    END LOOP;
END ChangeFirmName;
```

В этом исправленном коде добавлено закрытие курсора перед переоткрытием с обновленным значением `new_firm_name`, чтобы правильно использовать новое значение. Также добавлено условие `EXIT WHEN cur_firm_name%NOTFOUND;`, которое позволяет выйти из цикла, если запись не была найдена, что может помочь избежать лишних операций.

Проблема заключается в том, что после закрытия курсора `cur_firm_name`, попытка использовать его для проверки `IF cur_firm_name%NOTFOUND THEN` вызывает ошибку "invalid cursor". После закрытия курсора он становится недействительным, и обращение к нему вызывает ошибку.

Чтобы избежать этой ошибки, вам следует переставлять открытие курсора в начало цикла и помещать закрытие курсора в случае, когда он больше не нужен. Вот как это может быть исправлено:

```sql
PROCEDURE ChangeFirmName(old_name IN VARCHAR2, new_name IN VARCHAR2) IS
    CURSOR cur_firm_name(name_ VARCHAR2) IS
        SELECT * FROM Firms 
        WHERE firm_name = name_;

    firm_name_exists_exception EXCEPTION;
    new_firm_name VARCHAR2(50) := new_name;
    cur_firm_name_rec cur_firm_name%ROWTYPE;
BEGIN
    FOR i IN 1..10 LOOP
        BEGIN
            OPEN cur_firm_name(new_firm_name);
            FETCH cur_firm_name INTO cur_firm_name_rec;

            IF cur_firm_name%NOTFOUND THEN
                UPDATE Firms SET firm_name = new_firm_name WHERE firm_name = old_name; 
            ELSE
                RAISE firm_name_exists_exception;
            END IF;

            CLOSE cur_firm_name; -- закрытие курсора

            COMMIT;
            EXIT;

        EXCEPTION 
            WHEN firm_name_exists_exception THEN
                ROLLBACK;
                new_firm_name := new_firm_name || ' (1)';
                DBMS_OUTPUT.PUT_LINE('EXISTS ERROR');
