Для обработки ситуации, когда в курсоре не найдена информация при использовании оператора FETCH, вы можете использовать обработку исключения NO_DATA_FOUND. Исключение NO_DATA_FOUND генерируется, когда запрос курсора не возвращает результатов. 

Измените ваш код следующим образом для обработки ошибки "не найдена информация":

```sql
PROCEDURE find_max_frequency_computer(excluded_computer_id INT, computer_data OUT ComputerData) IS
    Cursor cur_freq IS
        SELECT c.computer_id, c.type_id, c.firm_id, c.frequency
        FROM Computers c
        WHERE c.computer_id <> excluded_computer_id
        ORDER BY c.frequency DESC;
BEGIN
    SAVEPOINT start_transaction;
    OPEN cur_freq;

    BEGIN
        FETCH cur_freq INTO computer_data;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            computer_data := NULL; -- или любое другое действие, которое определено для этой ситуации
    END;

    CLOSE cur_freq;
    COMMIT;
EXCEPTION 
    WHEN OTHERS THEN
        ROLLBACK TO start_transaction;
        DBMS_OUTPUT.PUT_LINE('find_max_frequency_computer ERROR');
END find_max_frequency_computer;
```

